export function parseCloseRoundInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[]
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>
): ParsedCloseRoundInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 13) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 13,
      }
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      signer: getNextAccount(),
      config: getNextAccount(),
      board: getNextAccount(),
      round: getNextAccount(),
      treasury: getNextAccount(),
      zincMint: getNextAccount(),
      curveAdminTokenAccount: getNextAccount(),
      bonanzaTokenAccount: getNextAccount(),
      roundZincPayoutTokenAccount: getNextAccount(),
      stockpileTokenAccount: getNextAccount(),
      stockpile: getNextAccount(),
      tokenProgram: getNextAccount(),
      systemProgram: getNextAccount(),
    },
    data: getCloseRoundInstructionDataDecoder().decode(instruction.data),
  };
}
